const payload = ($input.first().json.payload ?? $input.first().json);
if (!payload.report_type) return [{ json: { status: 'error', report: '', files: [], error: 'report_type is required' } }];
const report = `# ${payload.report_type} report

Period: ${payload.period ?? 'not specified'}

Data sources: ${(payload.data_sources ?? []).join(', ') || 'none configured'}

This is a safe V1 draft. Connect data sources before production.`;
return [{ json: { status: 'success', report, files: [], format: payload.format ?? 'markdown' } }];
